    department: "Finance",
    position: "Senior Financial Analyst",
    salary: 95000,
    hireDate: "2021-04-30",
    status: "active"
  },
  {
    id: "15",
    name: "Maria Garcia",
    email: "maria.garcia@company.com",
    department: "HR",
    position: "HR Specialist",
    salary: 68000,
    hireDate: "2023-08-12",
    status: "active"
  }
];

type SortField = "name" | "department" | "position" | "salary" | "hireDate";
type SortOrder = "asc" | "desc";

export function ResizableTable({
  title = "Employee",
  employees: initialEmployees = defaultEmployees,
  onEmployeeSelect,
  onColumnResize,
  className = "",
  enableAnimations = true
}: ResizableTableProps = {}) {
  const [selectedEmployees, setSelectedEmployees] = useState<string[]>([]);
  const [mounted, setMounted] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const [sortField, setSortField] = useState<SortField | null>(null);
  const [sortOrder, setSortOrder] = useState<SortOrder>("asc");
  const [showSortMenu, setShowSortMenu] = useState(false);
  const [showExportMenu, setShowExportMenu] = useState(false);

  const shouldReduceMotion = useReducedMotion();
  const { resolvedTheme } = useTheme();
  const isDark = mounted ? resolvedTheme !== "light" : true;
  const palette = getBjorkTablePalette(isDark);

  // Column width state with default values
  const [columnWidths, setColumnWidths] = useState<Record<string, number>>({
    checkbox: 50,
    name: 200,
    email: 220,
    department: 140,
    position: 180,
    salary: 120,
    hireDate: 120,
    status: 100
  });

  const ITEMS_PER_PAGE = 10;

  useEffect(() => {
    setMounted(true);
  }, []);

  const handleEmployeeSelect = (employeeId: string) => {
    setSelectedEmployees(prev => {
      if (prev.includes(employeeId)) {
        return prev.filter(id => id !== employeeId);
      } else {
        return [...prev, employeeId];
      }
    });
    if (onEmployeeSelect) {
      onEmployeeSelect(employeeId);
    }
  };

  const handleSelectAll = () => {
    if (selectedEmployees.length === paginatedEmployees.length) {
      setSelectedEmployees([]);
    } else {
      setSelectedEmployees(paginatedEmployees.map(e => e.id));
    }
  };

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortOrder(sortOrder === "asc" ? "desc" : "asc");
    } else {
      setSortField(field);
      setSortOrder("asc");
    }
    setShowSortMenu(false);
    setCurrentPage(1);
  };

  const sortedEmployees = useMemo(() => {
    if (!sortField) {
      return initialEmployees;
    }

    return [...initialEmployees].sort((a, b) => {
      let aVal: string | number = a[sortField];
      let bVal: string | number = b[sortField];

      if (sortField === "hireDate") {
        aVal = new Date(a.hireDate).getTime();
        bVal = new Date(b.hireDate).getTime();
      }

      if (aVal < bVal) return sortOrder === "asc" ? -1 : 1;
      if (aVal > bVal) return sortOrder === "asc" ? 1 : -1;
      return 0;
    });
  }, [initialEmployees, sortField, sortOrder]);

  const paginatedEmployees = useMemo(() => {
    const startIdx = (currentPage - 1) * ITEMS_PER_PAGE;
    return sortedEmployees.slice(startIdx, startIdx + ITEMS_PER_PAGE);
  }, [sortedEmployees, currentPage]);

  const totalPages = Math.ceil(sortedEmployees.length / ITEMS_PER_PAGE);

  const getStatusColor = (status: string) => {
    if (!mounted) {
      const statusMap: Record<string, { bgColor: string; borderColor: string; textColor: string; dotColor: string }> = {
        "active": getBjorkSignalPalette("green", true),
        "inactive": getBjorkSignalPalette("red", true),
        "on-leave": getBjorkSignalPalette("orange", true),
      };
      return statusMap[status];
    }

    const statusMap: Record<string, { bgColor: string; borderColor: string; textColor: string; dotColor: string }> = {
      "active": getBjorkSignalPalette("green", isDark),
      "inactive": getBjorkSignalPalette("red", isDark),
      "on-leave": getBjorkSignalPalette("orange", isDark),
    };

    return statusMap[status];
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0,
    }).format(amount);
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  const handleResize = (columnKey: string, { size }: { size: { width: number } }) => {
    const newWidth = Math.max(80, Math.min(400, size.width));

    setColumnWidths(prev => ({
      ...prev,
      [columnKey]: newWidth
    }));

    if (onColumnResize) {
      onColumnResize(columnKey, newWidth);
    }
  };

  const exportToCSV = () => {
    const headers = ["Name", "Email", "Department", "Position", "Salary", "Hire Date", "Status"];
    const rows = sortedEmployees.map(employee => [
      employee.name,
      employee.email,
      employee.department,
      employee.position,
      employee.salary,
      employee.hireDate,
      employee.status
    ]);

    const csvContent = [
      headers.join(","),
      ...rows.map(row => row.map(cell => `"${String(cell).replace(/"/g, '""')}"`).join(","))
    ].join("\n");

    const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `employees-${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  const exportToJSON = () => {
    const jsonContent = JSON.stringify(sortedEmployees, null, 2);
    const blob = new Blob([jsonContent], { type: "application/json;charset=utf-8;" });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `employees-${new Date().toISOString().split('T')[0]}.json`;
    link.click();
  };

  const shouldAnimate = enableAnimations && !shouldReduceMotion;

  const containerVariants = {
    visible: {
      transition: {
        staggerChildren: 0.04,
        delayChildren: 0.1,
      },
    }
  };

  const rowVariants = {
    hidden: { 
      opacity: 0, 
      y: 20,
      scale: 0.98,
      filter: "blur(4px)" 
    },
    visible: {
      opacity: 1,
      y: 0,
      scale: 1,
      filter: "blur(0px)",
      transition: {
        type: "spring",
        stiffness: 400,
        damping: 25,
        mass: 0.7,
      },
    },
    exit: {
      opacity: 0,
      y: -10,
      transition: { duration: 0.2 }
    }
  };


  return (
    <div className={`mx-auto w-full max-w-[1040px] ${className}`}>
      <div className="mb-4 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
        <div className="flex items-center gap-2">
        </div>

        <div className="flex items-center gap-2 flex-wrap">
          <div className="relative">
            <button 
              onClick={() => setShowSortMenu(!showSortMenu)}
              className={`flex items-center gap-2 rounded-md border px-3 py-1.5 text-sm transition-colors ${palette.control}`}
            >
              <svg width="14" height="14" viewBox="0 0 16 16" fill="none">
                <path d="M3 6L6 3L9 6M6 3V13M13 10L10 13L7 10M10 13V3" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
              Sort {sortField && <span className={`ml-1 rounded-sm px-1.5 py-0.5 text-xs ${palette.accentBg} ${palette.accent}`}>1</span>}
              <ChevronDown size={14} className="opacity-50" />
            </button>

            {showSortMenu && (
              <>
                <div 
                  className="fixed inset-0 z-10"
                  onClick={() => setShowSortMenu(false)}
                />
                <div className={`absolute right-0 z-20 mt-1 w-48 rounded-md border py-1 ${palette.menu}`}>
                  <button
                    onClick={() => handleSort("name")}
                    className={`w-full px-3 py-2 text-left text-sm transition-colors ${palette.menuItem} ${sortField === "name" ? palette.menuActive : ''}`}
                  >
                    Name {sortField === "name" && `(${sortOrder === "asc" ? "A-Z" : "Z-A"})`}
                  </button>
                  <button
                    onClick={() => handleSort("department")}
                    className={`w-full px-3 py-2 text-left text-sm transition-colors ${palette.menuItem} ${sortField === "department" ? palette.menuActive : ''}`}
                  >
                    Department {sortField === "department" && `(${sortOrder === "asc" ? "↑" : "↓"})`}
                  </button>
                  <button
                    onClick={() => handleSort("salary")}
                    className={`w-full px-3 py-2 text-left text-sm transition-colors ${palette.menuItem} ${sortField === "salary" ? palette.menuActive : ''}`}
                  >
                    Salary {sortField === "salary" && `(${sortOrder === "asc" ? "↑" : "↓"})`}
                  </button>
                  <button
                    onClick={() => handleSort("hireDate")}
                    className={`w-full px-3 py-2 text-left text-sm transition-colors ${palette.menuItem} ${sortField === "hireDate" ? palette.menuActive : ''}`}
                  >
                    Hire Date {sortField === "hireDate" && `(${sortOrder === "asc" ? "↑" : "↓"})`}
                  </button>
                </div>
              </>
            )}
          </div>

          <div className="relative">
            <button 
              onClick={() => setShowExportMenu(!showExportMenu)}
              className={`flex items-center gap-2 rounded-md border px-3 py-1.5 text-sm transition-colors ${palette.control}`}
            >
              <Download size={14} />
              Export
              <ChevronDown size={14} className="opacity-50" />
            </button>

            {showExportMenu && (
              <>
                <div 
                  className="fixed inset-0 z-10"
                  onClick={() => setShowExportMenu(false)}
                />
                <div className={`absolute right-0 z-20 mt-1 w-32 rounded-md border ${palette.menu}`}>
                  <button
                    onClick={() => {
                      exportToCSV();
                      setShowExportMenu(false);
                    }}
                    className={`flex w-full items-center gap-2 px-3 py-2 text-left text-sm transition-colors ${palette.menuItem}`}
                  >
                    CSV
                  </button>
                  <button
                    onClick={() => {
                      exportToJSON();
                      setShowExportMenu(false);
                    }}
                    className={`flex w-full items-center gap-2 border-t px-3 py-2 text-left text-sm transition-colors ${palette.divider} ${palette.menuItem}`}
                  >
                    JSON
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      </div>

      <div className={`relative overflow-hidden rounded-[18px] border ${palette.container}`}>
        <div className="overflow-x-auto">
          <div className="min-w-[1200px]">
            <div className={`flex border-b py-3 text-xs font-medium uppercase tracking-wide ${palette.header}`}>
              <div className={`flex items-center justify-center border-r pr-3 ${palette.divider}`} style={{ width: columnWidths.checkbox }}>
                <input 
                  type="checkbox" 
                  className="w-4 h-4 rounded border-border/40 cursor-pointer"
                  style={mounted ? {
                    accentColor: palette.checkboxAccent
                  } : {}}
                  checked={paginatedEmployees.length > 0 && selectedEmployees.length === paginatedEmployees.length}
                  onChange={handleSelectAll}
                />
              </div>

              <Resizable
                width={columnWidths.name}
                height={0}
                onResize={(e, data) => handleResize('name', data)}
                minConstraints={[80, 0]}
                maxConstraints={[400, 0]}
                handle={<div className="absolute bottom-0 right-0 top-0 w-1 cursor-col-resize bg-transparent transition-all hover:w-1.5 hover:bg-[#ec5c13]/45" />}
              >
                <div className={`relative flex items-center border-r px-3 ${palette.divider}`} style={{ width: columnWidths.name }}>
                  <span>{title}</span>
                </div>
              </Resizable>

              <Resizable
                width={columnWidths.email}
                height={0}
                onResize={(e, data) => handleResize('email', data)}
                minConstraints={[80, 0]}
                maxConstraints={[400, 0]}
                handle={<div className="absolute bottom-0 right-0 top-0 w-1 cursor-col-resize bg-transparent transition-all hover:w-1.5 hover:bg-[#ec5c13]/45" />}
              >
                <div className={`relative flex items-center gap-1.5 border-r px-3 ${palette.divider}`} style={{ width: columnWidths.email }}>
                  <svg width="14" height="14" viewBox="0 0 16 16" fill="none" className="opacity-40">
                    <rect x="2" y="4" width="12" height="8" rx="1" stroke="currentColor" strokeWidth="1.5" fill="none"/>
                    <path d="M2 6L8 9L14 6" stroke="currentColor" strokeWidth="1.5"/>
                  </svg>
                  <span>Email</span>
                </div>
              </Resizable>

              <Resizable
                width={columnWidths.department}
                height={0}
                onResize={(e, data) => handleResize('department', data)}
                minConstraints={[80, 0]}
                maxConstraints={[400, 0]}
                handle={<div className="absolute bottom-0 right-0 top-0 w-1 cursor-col-resize bg-transparent transition-all hover:w-1.5 hover:bg-[#ec5c13]/45" />}
              >
                <div className={`relative flex items-center gap-1.5 border-r px-3 ${palette.divider}`} style={{ width: columnWidths.department }}>
                  <svg width="14" height="14" viewBox="0 0 16 16" fill="none" className="opacity-40">
                    <path d="M2 2H4M2 8H6M2 14H8M10 2V14M14 4V14" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                  </svg>
                  <span>Department</span>
                </div>
              </Resizable>

              <Resizable
                width={columnWidths.position}
                height={0}
                onResize={(e, data) => handleResize('position', data)}
                minConstraints={[80, 0]}
                maxConstraints={[400, 0]}
                handle={<div className="absolute bottom-0 right-0 top-0 w-1 cursor-col-resize bg-transparent transition-all hover:w-1.5 hover:bg-[#ec5c13]/45" />}
              >
                <div className={`relative flex items-center gap-1.5 border-r px-3 ${palette.divider}`} style={{ width: columnWidths.position }}>
                  <svg width="14" height="14" viewBox="0 0 16 16" fill="none" className="opacity-40">
                    <path d="M3 3H13M3 8H13M3 13H9" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                  </svg>
                  <span>Position</span>
                </div>
              </Resizable>

              <Resizable
                width={columnWidths.salary}
                height={0}
                onResize={(e, data) => handleResize('salary', data)}
                minConstraints={[80, 0]}
                maxConstraints={[400, 0]}
                handle={<div className="absolute bottom-0 right-0 top-0 w-1 cursor-col-resize bg-transparent transition-all hover:w-1.5 hover:bg-[#ec5c13]/45" />}
              >
                <div className={`relative flex items-center gap-1.5 border-r px-3 ${palette.divider}`} style={{ width: columnWidths.salary }}>
                  <svg width="14" height="14" viewBox="0 0 16 16" fill="none" className="opacity-40">
                    <path d="M8 1L3 9H7L8 15L13 7H9L8 1Z" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                  </svg>
                  <span>Salary</span>
                </div>
              </Resizable>

              <Resizable
                width={columnWidths.hireDate}
                height={0}
                onResize={(e, data) => handleResize('hireDate', data)}
                minConstraints={[80, 0]}
                maxConstraints={[400, 0]}
                handle={<div className="absolute bottom-0 right-0 top-0 w-1 cursor-col-resize bg-transparent transition-all hover:w-1.5 hover:bg-[#ec5c13]/45" />}
              >
                <div className={`relative flex items-center gap-1.5 border-r px-3 ${palette.divider}`} style={{ width: columnWidths.hireDate }}>
                  <svg width="14" height="14" viewBox="0 0 16 16" fill="none" className="opacity-40">
                    <rect x="2" y="3" width="12" height="10" rx="1" stroke="currentColor" strokeWidth="1.5" fill="none"/>
                    <path d="M6 1V3M10 1V3" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                  </svg>
                  <span>Hire Date</span>
                </div>
              </Resizable>

              <div className="flex items-center gap-1.5 px-3" style={{ width: columnWidths.status }}>
                <svg width="14" height="14" viewBox="0 0 16 16" fill="none" className="opacity-40">
                  <circle cx="8" cy="8" r="2" stroke="currentColor" strokeWidth="1.5" fill="none"/>
                  <path d="M8 4V8L10 10" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                </svg>
                <span>Status</span>
              </div>


            </div>

            <AnimatePresence mode="wait">
              <motion.div
                key={`page-${currentPage}`}
                variants={shouldAnimate ? containerVariants : {}}
                initial={shouldAnimate ? "hidden" : "visible"}
                animate="visible"
              >
                {paginatedEmployees.map((employee) => (
                  <motion.div key={employee.id} variants={shouldAnimate ? rowVariants : {}}>
                    <div
                      className={`group relative flex border-b py-3.5 transition-all duration-150 ${
                        selectedEmployees.includes(employee.id)
                          ? palette.selectedRow
                          : palette.row
                      }`}
                    >
                      <div className={`flex items-center justify-center border-r pr-3 ${palette.divider}`} style={{ width: columnWidths.checkbox }}>
                        <input 
                          type="checkbox" 
                          className="w-4 h-4 rounded border-border/40 cursor-pointer"
                          style={mounted ? {
                            accentColor: palette.checkboxAccent
                          } : {}}
                          checked={selectedEmployees.includes(employee.id)}
                          onChange={() => handleEmployeeSelect(employee.id)}
                        />
                      </div>

                      <div className={`flex min-w-0 items-center border-r px-3 ${palette.divider}`} style={{ width: columnWidths.name }}>
                        <span className={`truncate text-sm ${palette.primaryText}`}>{employee.name}</span>
                      </div>

                      <div className={`flex min-w-0 items-center border-r px-3 ${palette.divider}`} style={{ width: columnWidths.email }}>
                        <a 
                          href={`mailto:${employee.email}`}
                          className={`truncate text-sm ${palette.accent}`}
                          onClick={(e) => e.stopPropagation()}
                        >
                          {employee.email}
                        </a>
                      </div>

                      <div className={`flex items-center border-r px-3 ${palette.divider}`} style={{ width: columnWidths.department }}>
                        <span className={`truncate text-sm ${palette.primaryText}`}>
                          {employee.department}
                        </span>
                      </div>

                      <div className={`flex min-w-0 items-center border-r px-3 ${palette.divider}`} style={{ width: columnWidths.position }}>
                        <span className={`truncate text-sm ${palette.primaryText}`}>
                          {employee.position}
                        </span>
                      </div>

                      <div className={`flex items-center border-r px-3 ${palette.divider}`} style={{ width: columnWidths.salary }}>
                        <span className={`text-sm font-semibold ${palette.primaryText}`}>
                          {formatCurrency(employee.salary)}
                        </span>
                      </div>

                      <div className={`flex items-center border-r px-3 ${palette.divider}`} style={{ width: columnWidths.hireDate }}>
                        <span className={`text-sm ${palette.primaryText}`}>
                          {formatDate(employee.hireDate)}
                        </span>
                      </div>

                      <div className="flex items-center px-3" style={{ width: columnWidths.status }}>
                        {(() => {
                          const { bgColor, borderColor, textColor, dotColor } = getStatusColor(employee.status);
                          return (
                            <div className={`inline-flex items-center gap-1.5 whitespace-nowrap rounded-md border px-2.5 py-1 text-xs font-medium ${bgColor} ${borderColor} ${textColor}`}>
                              <div className={`w-1.5 h-1.5 rounded-full ${dotColor}`}></div>
                              {employee.status.charAt(0).toUpperCase() + employee.status.slice(1).replace('-', ' ')}
                            </div>
                          );
                        })()}
                      </div>


                    </div>
                  </motion.div>
                ))}
              </motion.div>
            </AnimatePresence>
          </div>
        </div>

      </div>

      {totalPages > 1 && (
        <div className="mt-4 flex items-center justify-between px-2">
          <div className="text-xs text-muted-foreground/70">
            Page {currentPage} of {totalPages} • {sortedEmployees.length} employees
          </div>

          <div className="flex gap-1.5">
            <button
              onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
              disabled={currentPage === 1}
              className={`rounded-md border px-3 py-1.5 text-xs transition-colors disabled:cursor-not-allowed disabled:opacity-40 ${palette.control}`}
            >
              Previous
            </button>
            <button
              onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
              disabled={currentPage === totalPages}
              className={`rounded-md border px-3 py-1.5 text-xs transition-colors disabled:cursor-not-allowed disabled:opacity-40 ${palette.control}`}
            >
              Next
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

